import json
import re

# Load the full package info data
package_file = var_functions.query_db:18
with open(package_file, 'r') as f:
    packages = json.load(f)

# Load the project package version mapping
project_package_file = var_functions.query_db:16
with open(project_package_file, 'r') as f:
    project_packages = json.load(f)

# Parse package versions to find latest releases
package_releases = {}

for pkg in packages:
    name = pkg['Name']
    version = pkg['Version']

    # Parse VersionInfo JSON
    try:
        version_info = json.loads(pkg['VersionInfo'])
        is_release = version_info.get('IsRelease', False)
        ordinal = version_info.get('Ordinal', 0)

        if is_release:
            if name not in package_releases or ordinal > package_releases[name]['ordinal']:
                package_releases[name] = {
                    'version': version,
                    'ordinal': ordinal,
                    'system': pkg['System']
                }
    except:
        continue

