package_to_project = {}
for pp in project_packages:
    key = f"{pp['Name']}:{pp['Version']}"
    package_to_project[key] = pp['ProjectName']

# Add project info to package releases
releases_with_projects = []
for name, info in package_releases.items():
    key = f"{name}:{info['version']}"
    if key in package_to_project:
        releases_with_projects.append({
            'name': name,
            'version': info['version'],
            'project_name': package_to_project[key],
            'ordinal': info['ordinal']
        })

print('__RESULT__:')
print(json.dumps({
    'total_packages': len(package_releases),
    'packages_with_projects': len(releases_with_projects),
    'sample_releases': releases_with_projects[:5]
}, indent=2))

